// ============================================================
// Build the canon extraction prompt.
// Uses the canon_extractor prompt template.
// ============================================================

const project = $('Load Project').first().json;
const ingestion = $('Prepare Ingestion Input').first().json;
const canonData = $input.all();

// Flatten all canon query results
const existingCanon = {};
for (const item of canonData) {
  const j = item.json;
  if (Array.isArray(j)) {
    // Multi-statement results come as array
    // We'll pass them through
  }
}

const promptInput = {
  project_id: ingestion.project_id,
  chapter_id: ingestion.source_chapter_id || null,
  chapter_text: ingestion.content,
  existing_canon: existingCanon,
  input_type: ingestion.input_type,
  project: {
    title: project.name,
    genre: project.genre,
    style_profile: project.style_profile
  }
};

return [{
  json: {
    project: project,
    ingestion: ingestion,
    prompt_input: promptInput
  }
}];

// Parse AI response and check against locked canon
const response = $input.first().json;

let extracted;
try {
  if (response.choices && response.choices[0]) {
    extracted = JSON.parse(response.choices[0].message.content);
  } else {
    extracted = response;
  }
} catch (e) {
  throw new Error(`Failed to parse canon extraction: ${e.message}`);
}

// Flag items that need human review
const humanReviewItems = [];

// Check character updates against locked canon
(extracted.character_state_updates || []).forEach(u => {
  if (u.confidence < 0.7) {
    humanReviewItems.push({
      reason: `Low confidence character update for "${u.character_name}"`,
      content: JSON.stringify(u)
    });
  }
});

// Check new lore
(extracted.new_lore || []).forEach(l => {
  if (l.confidence < 0.7) {
    humanReviewItems.push({
      reason: `Low confidence lore: "${l.title}"`,
      content: JSON.stringify(l)
    });
  }
  if (l.should_lock && l.confidence < 0.9) {
    humanReviewItems.push({
      reason: `Lore marked for locking but confidence < 0.9: "${l.title}"`,
      content: JSON.stringify(l)
    });
  }
});

return [{
  json: {
    project_id: $('Prepare Ingestion Input').first().json.project_id,
    extracted: extracted,
    human_review_required: humanReviewItems.length > 0 ? humanReviewItems : [],
    has_human_review: humanReviewItems.length > 0
  }
}];

// ============================================================
// Build SQL UPDATE/INSERT statements for canon changes.
// Each statement respects locked canon (never overwrites).
// ============================================================

const data = $input.first().json;
const extracted = data.extracted;
const projectId = data.project_id;
const items = [];

// Character state updates
(extracted.character_state_updates || []).forEach(u => {
  if (u.confidence >= 0.7) {
    items.push({
      json: {
        table: 'character_states',
        sql: `INSERT INTO character_states (project_id, character_id, chapter_id, physical_state, emotional_state, knowledge_state, relationship_state, location_name, inventory_changes, confidence)
        SELECT $1, c.id, $2, $3, $4, $5, $6, $7, $8, $9
        FROM characters c WHERE c.project_id = $1 AND c.name = $10 AND c.is_locked = false
        ON CONFLICT DO NOTHING`,
        values: [projectId, u.chapter_id, u.physical_state, u.emotional_state, u.knowledge_state, JSON.stringify(u.relationship_state || {}), u.location_name, JSON.stringify(u.inventory_changes || []), u.confidence, u.character_name]
      }
    });
  }
});

// New lore
(extracted.new_lore || []).forEach(l => {
  if (l.confidence >= 0.7) {
    items.push({
      json: {
        table: 'world_lore',
        sql: `INSERT INTO world_lore (project_id, title, category, content, is_locked)
        VALUES ($1, $2, $3, $4, $5)
        ON CONFLICT (project_id, title) DO NOTHING`,
        values: [projectId, l.title, l.lore_type || 'general', l.content, l.should_lock && l.confidence >= 0.9]
      }
    });
  }
});

// Timeline events
(extracted.timeline_events || []).forEach(e => {
  if (e.confidence >= 0.7) {
    items.push({
      json: {
        table: 'timeline_events',
        sql: `INSERT INTO timeline_events (project_id, event_time_label, sequence_hint, event_summary, involved_characters, involved_locations, consequences, confidence)
        VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
        values: [projectId, e.event_time_label, e.sequence_hint || null, e.event_summary, e.involved_characters || [], e.involved_locations || [], e.consequences || [], e.confidence]
      }
    });
  }
});

// Foreshadowing updates
(extracted.foreshadowing_updates || []).forEach(f => {
  if (f.confidence >= 0.7) {
    items.push({
      json: {
        table: 'foreshadowing',
        sql: f.related_existing_id
          ? `UPDATE foreshadowing SET status = CASE WHEN $3 = 'resolved' THEN 'resolved' ELSE 'reinforced' END, updated_at = now() WHERE id = $1 AND project_id = $2 AND is_locked = false`
          : `INSERT INTO foreshadowing (project_id, clue_text, intended_payoff, status) VALUES ($1, $2, $3, 'introduced') ON CONFLICT DO NOTHING`,
        values: f.related_existing_id
          ? [f.related_existing_id, projectId, f.type]
          : [projectId, f.clue_text, f.intended_payoff || '']
      }
    });
  }
});

// Chapter summary as vector document
if (extracted.chapter_summary) {
  items.push({
    json: {
      table: 'vector_documents_prep',
      source_type: 'chapter_summary',
      title: `章节摘要: ${$('Load Project').first().json.title}`,
      content: extracted.chapter_summary,
      metadata: { extracted_at: new Date().toISOString() }
    }
  });
}

return items;

// ============================================================
// Summary of the ingestion run.
// ============================================================

const data = $('Parse & Validate Extraction').first().json;
const items = $input.all();

return [{
  json: {
    project_id: data.project_id,
    status: 'ingestion_complete',
    entities_updated: items.length,
    human_review_count: (data.human_review_required || []).length,
    human_review_items: data.human_review_required || [],
    message: data.has_human_review
      ? `Ingestion complete with ${data.human_review_required.length} items needing human review.`
      : 'Ingestion complete. All items applied.'
  }
}];
